func BenchmarkProcess(b *testing.B) {
	file, err := os.Open("/Users/ajitem/1brc/measurements.txt")
	if err != nil {
		b.Error(err)
	}
	defer file.Close()

	b.ReportAllocs()
	b.ResetTimer()

	for i := 0; i < b.N; i++ {
		err = Process(file, io.Discard)
		if err != nil {
			b.Error(err)
		}
	}
}
